package com.hospital.management.util;import java.time.*;import java.util.*;
/** Generates appointment slot start times contained fully inside a schedule window. */public final class TimeSlotGenerator{private TimeSlotGenerator(){}public static List<LocalTime> generateSlots(LocalTime start,LocalTime end,int minutes){if(start==null||end==null||!start.isBefore(end)||minutes<=0)throw new IllegalArgumentException("Valid start, end and duration are required");List<LocalTime>x=new ArrayList<>();for(LocalTime t=start;!t.plusMinutes(minutes).isAfter(end);t=t.plusMinutes(minutes))x.add(t);return List.copyOf(x);}}
